$ErrorActionPreference = "Stop"

Write-Host "`nRevPilot Core Implementation (13 files)" -ForegroundColor Cyan
Write-Host ("=" * 45) -ForegroundColor Cyan

# Base64-encoded files decoded at runtime
function Write-B64File($path, $b64) {
  $targetPath = if ([System.IO.Path]::IsPathRooted($path)) {
    $path
  } else {
    Join-Path $PSScriptRoot $path
  }
  $dir = Split-Path $targetPath -Parent
  if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
  $bytes = [System.Convert]::FromBase64String($b64)
  [System.IO.File]::WriteAllBytes($targetPath, $bytes)
  Write-Host "  + $targetPath" -ForegroundColor Green
}

